#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // sample previous uFrame
   ret = texture( sampler_rand00, vUv);

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 p0 = vec2 (.5,.6);
p0.x =  q15+.5;
p0.y =  q16+.5;

vec2 uv1 = (vUv-p0)*uAspect.xy;
uv1 = multiply(uv1,mat2(_qb));

float ang1 = atan(uv1.y, uv1.x);

float rad2 = length(uv1); //runder Tunnel
float rad2a = abs(uv1.x)+abs(uv1.y); //Rechtecktunnel
float rad2b = abs(abs(uv1.x)-abs(uv1.y))/1; //4 Tuerme

rad2 = abs(rad2b*uv1.x)*q30;
vec2 uv2 = vec2 (ang1/3.14, 1/rad2);

vec2 uvm = uv2 ;
uvm.y = uv2.y/8 + q9;
uvm.x = uv2.x;

vec3 crisp = texture(sampler_main,uvm);
vec3 blur = GetBlur1(fract(uvm - .0*crisp));

vec3 ret1c = crisp;
vec3 ret1b = (blur);

//*****************
vec2 uv4 = 64*(multiply(vUv,mat2(.6,.8,-.8,.6))+uTime/64);
vec3 smask = (texture(sampler_pw_noise_lq,uv4/256)).g-.9;
float stars = clamp01(.5/length(abs(fract(uv4)-.5))*smask);
float moon = clamp01(.01/length(uv1));
moon *= moon;

float mask_c = clamp01(128/pow(uv2.y,2));
float mask_b = clamp01(2/pow(uv2.y,1));

vec3 ret1 = ret1c * mask_c + ret1b * mask_b;

ret = ret1  + 0.2 * clamp01(.05/ (mask_c+.1))*vec3 (0,0,1)
+ clamp01((stars * stars +moon)* 1-mask_c*16);


  fragColor = ret;
}
